def separate_paren_groups(paren_string: str) -> List[str]:
    """
    Input to this function is a string containing multiple groups of nested parentheses.
    Your goal is to separate those groups into separate strings and return the list of those.
    Separate groups are balanced (each open brace is properly closed) and not nested within each other
    Ignore any spaces in the input string.

    Constraints:
    Input string contains only parentheses

    Examples:
        >>> separate_paren_groups("( ) (( )) (( )( ))")
        ["()", "(())", "(()())"]

    Exceptions: None
    """

    def group_parens(s):
        stack = []
        groups = []
        for c in s:
            if c == "(":
                stack.append(c)
            elif c == ")":
                if stack:
                    stack.pop()
                else:
                    groups.append(")")
        return "".join(stack + [")" for _ in range(len(groups))])

    def separate(s):
        result = []
        while s:
            group_start = s.find("(")
            group_end = s.find(")")
            if group_start == -1 or group_end == -1:
                raise ValueError("Invalid parentheses")
            group = s[:group_start] + s[group_start + 1 : group_end]
            result.append(group)
            s = s[group_end + 1 :]
        return result

    return separate(group_parens(paren_string))

